+"use client";
+
+import { useState } from "react";
+import { AnimatePresence, motion } from "framer-motion";
+import { useTranslation } from "react-i18next";
+import {
+  Briefcase,
+  Coins,
+  HeartPulse,
+  PartyPopper,
+  BookOpen,
+  X,
+} from "lucide-react";
+
+import { cn } from "@/lib/utils/cn";
+import { useLifesimPurchase } from "@/hooks/queries/use-lifesim";
+
+/**
